  5→// ---------------------------------------------------------------------------
  6→// Task status validation
  7→// ---------------------------------------------------------------------------
  8→
  9→export const VALID_TASK_STATUSES = [
 10→  "open", "todo", "ready", "in_progress", "blocked", "done", "completed",
 11→] as const;
 12→
 13→export type ValidTaskStatus = (typeof VALID_TASK_STATUSES)[number];
 14→
 15→export function validateTaskStatus(status: string): status is ValidTaskStatus {
 16→  return (VALID_TASK_STATUSES as readonly string[]).includes(status);
 17→}
