 85→// ---------------------------------------------------------------------------
 86→// Helpers
 87→// ---------------------------------------------------------------------------
 88→
 89→function toIso(value: Date | string | undefined): string {
 90→  if (!value) return "";
 91→  return value instanceof Date ? value.toISOString() : new Date(value).toISOString();
 92→}
