    status: task.status,
    ...(task.description ? { description: task.description } : {}),
    ...(task.priority ? { priority: task.priority } : {}),
    ...(task.owner_name ? { owner_name: task.owner_name } : {}),
    ...(task.deadline ? { deadline: toIso(task.deadline) } : {}),
